class Solution:
    def countSubMultisets(self, nums, l, r):
        MOD = 1000000007
        n = len(nums)
        seen = set()
        count = 0
        for mask in range(1 << n):
            subset = [nums[i] for i in range(n) if mask & (1 << i)]
            s = sum(subset)
            if l <= s <= r:
                key = tuple(sorted(subset))
                if key not in seen:
                    seen.add(key)
                    count += 1
        return count % MOD

