var countSubMultisets = function(nums, l, r) {
    const MODN = 1000000007;
    const cnt = new Map();
    for (const x of nums) cnt.set(x, (cnt.get(x) || 0) + 1);
    const zeros = cnt.get(0) || 0;
    cnt.delete(0);
    const values = Array.from(cnt.keys()).sort((a, b) => a - b);
    let dp = new Array(r + 1).fill(0);
    dp[0] = 1;
    for (const v of values) {
        const m = cnt.get(v);
        const newDp = dp.slice();
        for (let s = v; s <= r; s++) {
            newDp[s] = (newDp[s] + newDp[s - v]) % MODN;
            const idx = s - (m + 1) * v;
            if (idx >= 0) {
                newDp[s] = ((newDp[s] - dp[idx]) % MODN + MODN) % MODN;
            }
        }
        dp = newDp;
    }
    let total = 0;
    for (let s = l; s <= r; s++) total = (total + dp[s]) % MODN;
    total = (total * (zeros + 1)) % MODN;
    return total;
};
